sql:
SELECT h.*, ps.satisfaction_rating, ps.satisfaction_date
FROM hospitals h
JOIN patient_satisfaction ps ON h.hospital_id = ps.hospital_id;

SELECT hospitals.name, hospitals.city, ratings.hospital_overall_rating
FROM hospitals
INNER JOIN ratings ON hospitals.hospital_id = ratings.hospital_id
WHERE ratings.hospital_overall_rating = (
    SELECT MAX(hospital_overall_rating) FROM ratings
);

SELECT hospitals.name
FROM hospitals
JOIN regions ON hospitals.region_id = regions.region_id;

SELECT hospitals.name, hospitals.city, readmission_rates.readmission_rate
FROM hospitals
INNER JOIN readmission_rates ON hospitals.hospital_id = readmission_rates.hospital_id;

SELECT hospitals.name, hospitals.city, hospitals.state, ownership_types.ownership_type_name
FROM hospitals
JOIN ownership_types ON hospitals.ownership_type_id = ownership_types.ownership_type_id;

SELECT hospitals.name, hospitals.city, hospital_types.hospital_type_name
FROM hospitals
JOIN hospital_types ON hospitals.hospital_type_id = hospital_types.hospital_type_id;

external_knowledge:
- Hospital readmission rate is a key metric used to evaluate hospital performance; 
- Readmission refers to patients who are readmitted to the hospital within 30 days of discharge; 
- The year 2022 is significant in this query as it focuses on data from that specific year.

sql:
SELECT h.hospital_id, h.name, r.readmission_rate
FROM hospitals h
JOIN readmission_rates r ON h.hospital_id = r.hospital_id
WHERE r.readmission_rate > (
    SELECT AVG(readmission_rate) FROM readmission_rates
);
